<template><section class="page"><RouterLink :to="`/prompts/${id}`">← {{t('promptops.version.backDetail')}}</RouterLink><div v-if="loading" class="state">{{t('promptops.common.loading')}}</div><div v-else-if="!prompt" class="state">{{t('promptops.editor.promptNotFound')}}</div><template v-else><header><div><h2>{{t('promptops.version.history')}} — {{prompt.name}}</h2><p>{{t('promptops.version.currentVersion')}}: {{prompt.currentVersion}} · {{versions.length}} {{t('promptops.version.versions')}}</p></div><RouterLink class="primary" :to="`/prompts/${id}/edit`">{{t('promptops.actions.edit')}}</RouterLink></header><div v-if="!versions.length" class="state">{{t('promptops.version.empty')}}</div><article v-for="version in versions" :key="version.id" class="version"><div><RouterLink :to="`/prompts/${id}/versions/${version.id}`"><strong>{{version.versionNumber}}</strong></RouterLink><p>{{version.changeSummary}}</p><small>{{version.createdBy.name}} · {{formatDate(version.createdAt)}} · {{version.status}}</small></div><div class="actions"><span v-if="version.evaluationScore!==undefined">{{version.evaluationScore}}</span><button @click="restoreTarget=version">{{t('promptops.version.restore')}}</button></div></article></template><div v-if="restoreTarget" class="overlay" @click.self="restoreTarget=undefined"><form class="modal" @submit.prevent="restore"><h3>{{t('promptops.version.restore')}} {{restoreTarget.versionNumber}}</h3><label>{{t('promptops.editor.versionType')}}<select v-model="increment"><option value="minor">{{t('promptops.editor.minorVersion')}}</option><option value="major">{{t('promptops.editor.majorVersion')}}</option></select></label><label>{{t('promptops.editor.changeSummary')}}<input v-model.trim="summary" required/></label><div class="actions"><button type="button" @click="restoreTarget=undefined">{{t('promptops.common.cancel')}}</button><button class="primary" :disabled="saving">{{t('promptops.version.restore')}}</button></div></form></div></section></template>
<script setup lang="ts">import{onMounted,ref}from'vue';import{RouterLink,useRoute,useRouter}from'vue-router';import{useI18n}from'vue-i18n';import type{PromptOpsPrompt as Prompt,PromptOpsPromptVersion as PromptVersion}from'@prompt-optimizer/core';import{usePromptOpsServices}from'../../services/promptops';const{t}=useI18n(),route=useRoute(),router=useRouter(),services=usePromptOpsServices(),id=String(route.params.id);const prompt=ref<Prompt>(),versions=ref<PromptVersion[]>([]),loading=ref(true),saving=ref(false),restoreTarget=ref<PromptVersion>(),summary=ref('Restore historical version'),increment=ref<'minor'|'major'>('minor');onMounted(async()=>{[prompt.value,versions.value]=await Promise.all([services.promptRepository.getById(id),services.promptVersionRepository.listByPromptId(id)]);loading.value=false});const restore=async()=>{if(!restoreTarget.value)return;saving.value=true;try{const version=await services.promptEditorService.restoreAsNew(id,restoreTarget.value.id,{changeSummary:summary.value,increment:increment.value});await router.push(`/prompts/${id}/versions/${version.id}`)}finally{saving.value=false}};const formatDate=(x:string)=>new Intl.DateTimeFormat(undefined,{dateStyle:'medium',timeStyle:'short'}).format(new Date(x))</script>
<style scoped>.page{display:grid;gap:15px}.page>a,.version a{color:#2563eb;text-decoration:none}header,.version,.actions{display:flex;justify-content:space-between;gap:12px;align-items:center}header h2{margin:0}.version{padding:17px;border:1px solid #e5e7eb;border-radius:10px;background:var(--n-color,#fff)}.version p{margin:6px 0}.version small{color:#64748b}.primary,button,input,select{padding:8px 11px;border:1px solid #d1d5db;border-radius:7px;background:var(--n-color,#fff);color:inherit}.primary{background:#2563eb;color:#fff;text-decoration:none}.state{text-align:center;padding:55px}.overlay{position:fixed;inset:0;background:#0008;display:grid;place-items:center}.modal{width:min(460px,90vw);padding:22px;background:var(--n-color,#fff);display:grid;gap:14px;border-radius:10px}.modal label{display:grid;gap:6px}</style>
